INSERT INTO MonAn (mamonan, tenmonan, mota, phanloai, isdeleted) VALUES (52, 'Bánh mì gà nướng', 'Bánh mì gà nướng mất khoảng 45 phút để thực hiện từ đầu đến cuối. Một phần ăn cung cấp khoảng 28g protein, 14g chất béo và có chi phí khoảng 2,58 USD.', 'Bữa trưa', 0) ON CONFLICT DO NOTHING;
