INSERT INTO DinhDuong (madinhduong, mamonan, calo, protein, chatbeo, carbohydrate, vitamin) VALUES (50, 50, '480.00', '32.00', '25.00', '28.00', 'B6, B12, Kẽm') ON CONFLICT DO NOTHING;
INSERT INTO DinhDuong (madinhduong, mamonan, calo, protein, chatbeo, carbohydrate, vitamin) VALUES (51, 51, '280.00', '12.50', '18.00', '22.00', 'Vitamin B12, Sắt, Kẽm, Magie') ON CONFLICT DO NOTHING;
INSERT INTO DinhDuong (madinhduong, mamonan, calo, protein, chatbeo, carbohydrate, vitamin) VALUES (52, 52, '448.20', '27.90', '14.20', '47.50', '') ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (1, 1, 'Ninh xương bò 4-6 tiếng với gừng, hành nướng, quế, hồi, thảo quả. Trụng bánh phở, xếp thịt bò, chan nước dùng. Ăn kèm giá đỗ, rau thơm, chanh, ớt.', 120, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (2, 2, 'Ninh xương heo, bò với sả, ớt, mắm ruốc. Thêm chả cua, huyết. Trụng bún, chan nước dùng nóng. Ăn kèm rau sống, chanh.', 150, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (3, 3, 'Ướp sườn với sả, tỏi, nước mắm, đường, nướng trên than. Nấu cơm tấm. Chiên trứng ốp la. Bày ra đĩa với bì, chả, đồ chua, nước mắm pha.', 45, 1) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (4, 4, 'Nướng giòn bánh mì. Phết bơ, pate lên ruột bánh. Xếp thịt nguội, chả lụa, dưa leo, đồ chua, rau mùi, ớt. Rưới nước tương.', 15, 1) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (5, 5, 'Luộc tôm, thịt. Nhúng bánh tráng nước ấm, xếp rau, bún, tôm, thịt rồi cuốn chặt. Pha nước chấm mắm nêm hoặc tương đen.', 30, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (6, 6, 'Trộn nhân thịt heo xay, mộc nhĩ, miến, cà rốt, hành. Cuốn bánh tráng, chiên vàng giòn. Ăn kèm nước mắm chua ngọt và rau sống.', 45, 4) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (7, 7, 'Ướp thịt ba chỉ và thịt xay viên với nước mắm, đường, tỏi, tiêu. Nướng trên than hoa. Pha nước chấm chua ngọt với đu đủ, cà rốt. Ăn với bún và rau sống.', 60, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (8, 8, 'Pha bột bánh xèo với nước cốt dừa, bột nghệ. Đổ bột mỏng trên chảo nóng, thêm tôm, thịt, giá. Gấp đôi, chiên giòn. Cuốn rau sống, chấm nước mắm.', 40, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (9, 9, 'Ninh xương heo lấy nước dùng trong. Trụng hủ tiếu, xếp tôm, thịt băm, gan. Chan nước dùng, thêm hành phi, tỏi phi.', 90, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (10, 10, 'Nấu nước dùng từ xương, tôm. Ướp thịt gà hoặc heo với nghệ. Trụng mì, chan nước dùng vừa xâm xấp. Rắc đậu phộng rang, bánh tráng nướng, rau sống.', 60, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (11, 11, 'Luộc sợi cao lầu. Thái thịt heo xá xíu. Xếp mì, thịt, rau sống, giá. Rưới nước xá xíu và dầu phi hành.', 50, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (12, 12, 'Giã cua đồng lọc lấy nước và gạch. Nấu nước dùng với cà chua, mắm tôm. Cho riêu cua vào, thêm đậu phụ, huyết. Trụng bún, chan nước dùng.', 90, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (13, 13, 'Nấu nước dùng với thơm, cà chua, me. Cho cá lóc vào, thêm đậu bắp, giá đỗ, bạc hà. Nêm nước mắm, đường. Rắc rau ngổ.', 30, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (14, 14, 'Rim đường thắng màu caramel. Cho thịt ba chỉ vào đảo đều. Đổ nước dừa tươi, nước mắm, tiêu. Thêm trứng luộc. Kho liu riu 1-2 tiếng đến khi mềm.', 90, 4) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (15, 15, 'Ướp cá basa với nước mắm, đường, tiêu, nước hàng. Phi hành tỏi trong nồi đất, xếp cá vào. Kho lửa nhỏ đến khi cá thấm gia vị, nước kho sánh lại.', 45, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (16, 16, 'Ướp gà với mật ong, nước mắm, tỏi, gừng, ngũ vị hương 2 tiếng. Nướng ở 200°C trong 45-60 phút, quét thêm mật ong giữa chừng.', 90, 4) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (17, 17, 'Thái bò thành khối vuông, ướp nước tương, tỏi, tiêu, đường. Phi tỏi bơ, cho bò vào xào lửa lớn nhanh tay. Bò chín tái vừa mềm.', 20, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (18, 18, 'Ướp gà với sả băm, ớt, nước mắm, đường. Phi sả ớt thơm, cho gà vào xào lửa lớn. Thêm ít nước, rim đến khi cạn nước, gà thấm gia vị.', 30, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (19, 19, 'Xào tôm, lạp xưởng trước. Cho cơm nguội vào xào lửa lớn, tạo không gian cho trứng. Thêm đậu Hà Lan, cà rốt, nêm nước mắm, tiêu.', 20, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (20, 20, 'Pha bột gạo với nước, tráng mỏng trên vải hấp. Nhân thịt xay xào mộc nhĩ, hành. Cuộn bánh, ăn kèm chả quế và nước mắm chua ngọt.', 60, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (21, 21, 'Ngâm nếp 4 tiếng, hấp chín. Đậu xanh hấp chín tán nhuyễn. Xếp xôi, đậu xanh, rưới mỡ hành phi. Rắc hành phi giòn.', 60, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (22, 22, 'Ướp bò với sả, ớt, bột cà ri. Phi hành tỏi, xào bò. Thêm nước, cà rốt, khoai tây. Hầm liu riu 2 tiếng đến khi bò mềm.', 120, 4) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (23, 23, 'Nấu nước dùng với sả, lá chanh, galangal, ớt, cà chua. Cho nước cốt chanh, nước mắm. Nhúng hải sản, nấm, rau.', 40, 4) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (24, 24, 'Luộc gà lấy nước dùng trong. Cho lá é, sả, gừng vào nước dùng. Thái gà miếng vừa. Nhúng rau, nấm ăn kèm bún.', 45, 4) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (25, 25, 'Ướp cá lăng với nghệ, sả, mẻ. Chiên cá sơ, sau đó xào với thì là, hành lá trên chảo nóng. Ăn kèm bún, mắm tôm, đậu phộng.', 40, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (26, 26, 'Nấu nước dùng từ cua, gạch cua. Trụng sợi bánh canh, chan nước dùng. Thêm thịt cua, hành lá, tiêu.', 60, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (27, 27, 'Ướp thịt heo với sả, tỏi, nước mắm, mật ong. Nướng trên than. Bày bún, rau sống, thịt nướng, đậu phộng, hành phi. Rưới nước mắm chua ngọt.', 40, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (28, 28, 'Luộc gà ta, lấy nước dùng trong. Trụng bánh phở, xếp thịt gà xé, chan nước dùng. Thêm hành lá, rau thơm, chanh, ớt.', 90, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (29, 29, 'Nấu nước dùng từ mắm cá linh, lọc trong. Thêm tôm, mực, cá, thịt heo. Trụng bún, chan nước dùng, thêm rau sống.', 60, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (30, 30, 'Nấu cháo trắng nhừ. Luộc lòng heo, thái miếng. Cho lòng, huyết vào cháo. Nêm nước mắm, tiêu. Rắc hành lá, giá đỗ.', 60, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (31, 31, 'Luộc gà, xé thịt. Nấu gạo với nước luộc gà đến nhừ. Cho thịt gà xé vào. Rắc hành lá, gừng thái sợi, tiêu.', 45, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (32, 32, 'Xay thịt heo với tỏi, đường, bột nổi. Viên thành viên, nướng trên than. Cuốn bánh tráng với rau sống, bún, chấm nước chấm.', 40, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (33, 33, 'Ướp bò với tiêu, bơ, nước tương. Áp chảo trên đĩa gang nóng. Thêm trứng ốp la, pate, bánh mì. Ăn ngay khi còn nóng xèo xèo.', 20, 1) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (34, 34, 'Luộc gà, lấy nước luộc nấu cơm. Gà xé phay trộn hành tây, rau răm. Ăn kèm canh, đồ chua.', 50, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (35, 35, 'Thắng đường caramel. Cho thịt ba chỉ kho với nước dừa, nước mắm. Thêm trứng cút luộc. Kho liu riu đến mềm.', 60, 4) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (36, 36, 'Luộc gà, xé sợi. Thái bắp cải, hành tây sợi mỏng. Trộn gà, rau với nước mắm chua ngọt. Rắc đậu phộng, rau răm.', 25, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (37, 37, 'Chiên sơ sườn. Xào cà chua, dứa với đường, giấm, nước mắm tạo sốt. Cho sườn vào rim đến khi sốt sánh đều.', 35, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (38, 38, 'Phi tỏi băm thơm với dầu nóng. Cho rau muống vào xào lửa lớn nhanh tay. Nêm nước mắm, đường. Rau chín tới vẫn giòn xanh.', 10, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (39, 39, 'Chiên đậu hũ vàng giòn. Xào cà chua nhuyễn với hành tỏi. Cho đậu hũ vào rim với sốt cà chua, nêm nước mắm. Rắc hành lá.', 20, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (40, 40, 'Khoét ruột khổ qua, nhồi thịt heo xay trộn mộc nhĩ, miến. Nấu nước dùng, cho khổ qua nhồi vào nấu chín mềm. Nêm nước mắm.', 40, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (41, 41, 'Phi hành tỏi, cho tôm vào xào sơ. Đổ nước dừa, nước mắm, đường, tiêu. Rim lửa nhỏ đến khi nước sánh, tôm thấm gia vị.', 25, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (42, 42, 'Ướp gà với nước mắm, đường, tiêu. Phi gừng thái sợi thơm. Cho gà vào kho với nước, rim đến khi cạn nước, gà thấm.', 40, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (43, 43, 'Pha bột gạo với nước, đổ vào chén nhỏ hấp chín. Làm nhân tôm chấy phi hành. Rưới lên bánh, thêm mỡ hành, ăn kèm nước mắm.', 40, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (44, 44, 'Cắt bánh tráng sợi. Trộn với trứng cút, khô bò, xoài xanh, rau răm. Thêm tương ớt, nước mắm chua ngọt, sa tế. Trộn đều.', 10, 1) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (45, 45, 'Chiên đậu hũ vàng giòn. Bày bún lá, đậu hũ, chả cốm, thịt luộc. Pha mắm tôm với chanh, đường, ớt, quất.', 20, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (46, 46, 'Luộc hến lấy nước và thịt. Xào hến với gia vị. Bày cơm nguội, hến xào, rau sống, đậu phộng. Rưới nước hến, mắm ruốc ớt.', 30, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (47, 47, 'Pha bột gạo với nước cốt dừa, bột nghệ. Đổ bột vào khuôn nóng, cho tôm lên. Chiên vàng giòn. Ăn kèm rau sống, nước mắm chua ngọt.', 30, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (48, 48, 'Ướp thịt ba rọi với ngũ vị hương, muối, tỏi. Để da khô, xăm lỗ nhỏ. Quay ở 220°C đến khi da phồng giòn vàng.', 120, 4) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (49, 49, 'Nấu nước dùng từ mắm cá, lọc trong. Chiên cá lóc vàng. Trụng bún, chan nước dùng, xếp cá chiên. Ăn kèm rau sống.', 50, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (50, 50, 'Ướp đùi gà với tỏi, tiêu. Chiên vàng giòn. Nấu sốt nước mắm, đường, tỏi phi, ớt. Rưới sốt lên gà, rắc hành phi.', 40, 2) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (51, 51, 'Sơ chế nguyên liệu bằng cách ngâm nở miến và mộc nhĩ rồi băm nhỏ, cà rốt bào sợi, sau đó trộn đều tất cả với thịt băm, tôm, trứng và gia vị để làm phần nhân. Trải bánh tráng ra mặt phẳng, thấm một ít nước cho mềm rồi cho nhân vào giữa và cuộn tròn chặt tay. Đun nóng dầu ăn trong chảo và chiên chả giò ở lửa vừa cho đến khi lớp vỏ chuyển màu vàng nâu và đạt độ giòn rụm, sau đó vớt ra để ráo dầu trước khi trình bày.', 40, 4) ON CONFLICT DO NOTHING;
INSERT INTO CongThuc (macongthuc, mamonan, huongdan, thoigiannau, khauphan) VALUES (52, 52, 'Chưa có hướng dẫn chi tiết', 45, 6) ON CONFLICT DO NOTHING;
